```class Solution {
public:
    int maximumXOR(vector<int>& nums) {
        int result = 0;
        for (int i = 0; i < nums.size(); i++) {
            int xor = 0;
            for (int j = 0; j < nums.size(); j++) {
                xor = nums[i] XOR nums[j];
                result = max(result, xor);
            }
        }
        return result;
    }
};
